    bool EditorManager::Initialize(HWND hwnd, ID3D11Device* device, ID3D11DeviceContext* context, EntityRegistry* registry) {
        // Setup ImGui context
        IMGUI_CHECKVERSION();
        ImGui::CreateContext();
        
        ImGuiIO& io = ImGui::GetIO();
        io.ConfigFlags |= ImGuiConfigFlags_NavEnableKeyboard;
        io.ConfigFlags |= ImGuiConfigFlags_DockingEnable;
        io.ConfigFlags |= ImGuiConfigFlags_ViewportsEnable;
        
        // Setup style
        ImGui::StyleColorsDark();
        
        // When viewports are enabled we tweak WindowRounding/WindowBg
        ImGuiStyle& style = ImGui::GetStyle();
        if (io.ConfigFlags & ImGuiConfigFlags_ViewportsEnable) {
            style.WindowRounding = 0.0f;
            style.Colors[ImGuiCol_WindowBg].w = 1.0f;
        }

        // Platform/Renderer bindings
        if (!ImGui_ImplWin32_Init(hwnd)) {
            std::cerr << "Failed to initialize ImGui Win32 implementation" << std::endl;
            return false;
        }
        
        if (!ImGui_ImplDX11_Init(device, context)) {
            std::cerr << "Failed to initialize ImGui DX11 implementation" << std::endl;
            return false;
        }

        m_registry = registry;
        m_device = device;
        m_context = context;
        m_initialized = true;

        // Register default editor windows
        AddWindow<DockSpaceWindow>();
        AddWindow<ToolbarWindow>();
        AddWindow<HierarchyWindow>(m_registry, [this](Entity e) { SelectEntity(e); });
        AddWindow<InspectorWindow>(m_registry);
        AddWindow<AssetBrowserWindow>();
        AddWindow<ViewportWindow>(m_graphics);
        
        if (m_collaborativeDevelopment) {
            AddWindow<CollaborationWindow>(m_collaborativeDevelopment);
        }

        std::cout << "EditorManager initialized successfully" << std::endl;
        return true;
    }

    void EditorManager::Shutdown() {
        if (!m_initialized) return;

        // Shutdown ImGui
        ImGui_ImplDX11_Shutdown();
        ImGui_ImplWin32_Shutdown();
        ImGui::DestroyContext();
        
        // Clear windows
        m_windows.clear();
        
        m_initialized = false;
        std::cout << "EditorManager shutdown complete" << std::endl;
    }

    void EditorManager::NewFrame() {
        if (!m_initialized) return;

        ImGui_ImplDX11_NewFrame();
        ImGui_ImplWin32_NewFrame();
        ImGui::NewFrame();
    }

    void EditorManager::Render() {
        if (!m_initialized) return;

        // Render docking space first
        for (auto& window : m_windows) {
            if (strcmp(window->GetName(), "DockSpace") == 0) {
                window->Render();
                break;
            }
        }

        // Render main menu bar
        RenderMainMenuBar();

        // Render other windows
        for (auto& window : m_windows) {
            const char* name = window->GetName();
            if (strcmp(name, "DockSpace") != 0) {
                if (window->IsVisible()) {
                    window->Render();
                }
            }
        }

        // Render performance overlay
        if (m_showPerformanceOverlay) {
            RenderPerformanceOverlay();
        }

        // Show ImGui demo if requested
        if (m_showDemoWindow) {
            ImGui::ShowDemoWindow(&m_showDemoWindow);
        }

        // Handle editor shortcuts
        HandleShortcuts();

        ImGui::Render();
    }

    void EditorManager::Present() {
        if (!m_initialized) return;

        ImGui_ImplDX11_RenderDrawData(ImGui::GetDrawData());

        // Handle multi-viewport rendering
        ImGuiIO& io = ImGui::GetIO();
        if (io.ConfigFlags & ImGuiConfigFlags_ViewportsEnable) {
            ImGui::UpdatePlatformWindows();
            ImGui::RenderPlatformWindowsDefault();
        }
    }

    void EditorManager::SelectEntity(Entity entity) {
        m_selectedEntity = entity;
        
        // Notify all windows of entity selection
        for (auto& window : m_windows) {
            window->OnEntitySelected(entity);
        }
    }

    void EditorManager::RemoveWindow(const char* name) {
        m_windows.erase(
            std::remove_if(m_windows.begin(), m_windows.end(),
                [&](auto& w) { return strcmp(w->GetName(), name) == 0; }),
            m_windows.end()
        );
    }

    EditorWindow* EditorManager::GetWindow(const char* name) {
        for (auto& w : m_windows) {
            if (strcmp(w->GetName(), name) == 0) {
                return w.get();
            }
        }
        return nullptr;
    }

    bool EditorManager::IsMouseOverEditor() const {
        ImGuiIO& io = ImGui::GetIO();
        return io.WantCaptureMouse;
    }

    bool EditorManager::WantCaptureKeyboard() const {
        ImGuiIO& io = ImGui::GetIO();
        return io.WantCaptureKeyboard;
    }

    void EditorManager::RenderMainMenuBar() {
        if (ImGui::BeginMainMenuBar()) {
            if (ImGui::BeginMenu("File")) {
                if (ImGui::MenuItem("New Scene", "Ctrl+N")) {
                    // Handle new scene
                }
                if (ImGui::MenuItem("Open Scene", "Ctrl+O")) {
                    // Handle open scene
                }
                if (ImGui::MenuItem("Save Scene", "Ctrl+S")) {
                    // Handle save scene
                }
                ImGui::Separator();
                if (ImGui::MenuItem("Exit", "Alt+F4")) {
                    PostQuitMessage(0);
                }
                ImGui::EndMenu();
            }

            if (ImGui::BeginMenu("Edit")) {
                if (ImGui::MenuItem("Undo", "Ctrl+Z")) {
                    // Handle undo
                }
                if (ImGui::MenuItem("Redo", "Ctrl+Y")) {
                    // Handle redo
                }
                ImGui::EndMenu();
            }

            if (ImGui::BeginMenu("View")) {
                for (auto& window : m_windows) {
                    if (strcmp(window->GetName(), "DockSpace") != 0) {
                        bool visible = window->IsVisible();
                        if (ImGui::MenuItem(window->GetName(), nullptr, &visible)) {
                            window->SetVisible(visible);
                        }
                    }
                }
                ImGui::Separator();
                ImGui::MenuItem("Performance Overlay", nullptr, &m_showPerformanceOverlay);
                ImGui::MenuItem("ImGui Demo", nullptr, &m_showDemoWindow);
                ImGui::EndMenu();
            }

            if (ImGui::BeginMenu("Tools")) {
                if (ImGui::MenuItem("Shader Reload", "F5")) {
                    // Handle shader reload
                }
                if (ImGui::MenuItem("Asset Refresh", "F6")) {
                    // Handle asset refresh
                }
                ImGui::EndMenu();
            }

            if (ImGui::BeginMenu("Help")) {
                if (ImGui::MenuItem("About")) {
                    m_showAboutDialog = true;
                }
                ImGui::EndMenu();
            }

            ImGui::EndMainMenuBar();
        }

        // Handle dialogs
        if (m_showAboutDialog) {
            RenderAboutDialog();
        }
    }

    void EditorManager::RenderPerformanceOverlay() {
        ImGuiIO& io = ImGui::GetIO();
        ImGuiWindowFlags window_flags = ImGuiWindowFlags_NoDecoration | 
                                       ImGuiWindowFlags_AlwaysAutoResize | 
                                       ImGuiWindowFlags_NoSavedSettings | 
                                       ImGuiWindowFlags_NoFocusOnAppearing | 
                                       ImGuiWindowFlags_NoNav;

        const float PAD = 10.0f;
        const ImGuiViewport* viewport = ImGui::GetMainViewport();
        ImVec2 work_pos = viewport->WorkPos;
        ImVec2 work_size = viewport->WorkSize;
        ImVec2 window_pos, window_pos_pivot;
        window_pos.x = work_pos.x + work_size.x - PAD;
        window_pos.y = work_pos.y + PAD;
        window_pos_pivot.x = 1.0f;
        window_pos_pivot.y = 0.0f;

        ImGui::SetNextWindowPos(window_pos, ImGuiCond_Always, window_pos_pivot);
        window_flags |= ImGuiWindowFlags_NoMove;

        ImGui::SetNextWindowBgAlpha(0.35f);
        if (ImGui::Begin("Performance Overlay", &m_showPerformanceOverlay, window_flags)) {
            ImGui::Text("SparkEngine Performance");
            ImGui::Separator();
            ImGui::Text("FPS: %.1f", io.Framerate);
            ImGui::Text("Frame Time: %.3f ms", 1000.0f / io.Framerate);
            
            if (m_graphics) {
                const auto& stats = m_graphics->GetRenderStats();
                ImGui::Text("Draw Calls: %u", stats.drawCalls);
                ImGui::Text("Triangles: %u", stats.triangles);
                ImGui::Text("Vertices: %u", stats.vertices);
            }
        }
        ImGui::End();
    }

    void EditorManager::RenderAboutDialog() {
        ImGui::SetNextWindowSize(ImVec2(400, 200), ImGuiCond_FirstUseEver);
        if (ImGui::Begin("About SparkEngine", &m_showAboutDialog, ImGuiWindowFlags_NoDocking)) {
            ImGui::Text("SparkEngine");
            ImGui::Text("Version 1.0.0");
            ImGui::Separator();
            ImGui::Text("A modern, collaborative game engine");
            ImGui::Text("Built with DirectX 11, ImGui, and EnTT");
            ImGui::Separator();
            if (ImGui::Button("Close")) {
                m_showAboutDialog = false;
            }
        }
        ImGui::End();
    }

